# ---------------------------------------------------------------------------
# Shared AWS client factory (lazy-initialized, reused across invocations)
# ---------------------------------------------------------------------------
class AWSClientFactory:
    """Singleton factory for AWS service clients.
    
    Clients are created once per Lambda container lifetime and reused,
    taking advantage of connection pooling and keep-alive.
    All clients operate under the shared IAM role attached to the function.
    """

    _clients = {}

    @classmethod
    def get_client(cls, service_name, region_name=None):
        region = region_name or os.environ.get("AWS_REGION", "us-east-1")
        key = f"{service_name}:{region}"
        if key not in cls._clients:
            cls._clients[key] = boto3.client(service_name, region_name=region)
        return cls._clients[key]

    @classmethod
    def get_resource(cls, service_name, region_name=None):
        region = region_name or os.environ.get("AWS_REGION", "us-east-1")
        key = f"resource:{service_name}:{region}"
        if key not in cls._clients:
            cls._clients[key] = boto3.resource(service_name, region_name=region)
        return cls._clients[key]


# Convenience accessors
def dynamodb_client():
    return AWSClientFactory.get_client("dynamodb")


def dynamodb_resource():
    return AWSClientFactory.get_resource("dynamodb")


def s3_client():
    return AWSClientFactory.get_client("s3")


def sns_client():
    return AWSClientFactory.get_client("sns")


def sqs_client():
    return AWSClientFactory.get_client("sqs")


# ---------------------------------------------------------------------------
# Shared decorators & utilities used by all microservices
# ---------------------------------------------------------------------------
def correlation_id_from_event(event):
    """Extract or generate a correlation ID for distributed tracing."""
    headers = event.get("headers") or {}
    # Check common header patterns (case-insensitive)
    for key in ("x-correlation-id", "X-Correlation-Id", "x-request-id", "X-Request-Id"):
        if key in headers:
            return headers[key]
    # Check SQS message attributes
    if "Records" in event and event["Records"]:
        record = event["Records"][0]
        msg_attrs = record.get("messageAttributes") or {}
        if "correlationId" in msg_attrs:
            return msg_attrs["correlationId"].get("stringValue", str(uuid.uuid4()))
    return str(uuid.uuid4())


def lambda_middleware(func):
    """Shared middleware decorator for all microservice Lambda handlers.
    
    Provides:
    - Correlation ID injection
    - Structured logging context
    - Error handling with consistent response format
    - Duration tracking
    """
    @wraps(func)
    def wrapper(event, context):
        correlation_id = correlation_id_from_event(event)
        start_time = time.time()

        log_context = {
            "service": SERVICE_NAME,
            "environment": ENVIRONMENT,
            "correlation_id": correlation_id,
            "function_name": context.function_name,
            "request_id": context.aws_request_id,
            "shared_role": SHARED_ROLE_ARN or "attached-via-template",
        }

        logger.info(json.dumps({
            **log_context,
            "message": "Lambda invocation started",
            "event_source": _detect_event_source(event),
            "remaining_time_ms": context.get_remaining_time_in_millis(),
        }))

        try:
            result = func(event, context, correlation_id=correlation_id)
            duration_ms = (time.time() - start_time) * 1000

            logger.info(json.dumps({
                **log_context,
                "message": "Lambda invocation completed",
                "duration_ms": round(duration_ms, 2),
            }))

            return result

        except ClientError as e:
            duration_ms = (time.time() - start_time) * 1000
            error_code = e.response["Error"]["Code"]
            error_message = e.response["Error"]["Message"]

            logger.error(json.dumps({
                **log_context,
                "message": "AWS service error",
                "error_code": error_code,
                "error_message": error_message,
                "duration_ms": round(duration_ms, 2),
            }))

            return _error_response(502, f"AWS service error: {error_code}", correlation_id)

        except ValueError as e:
            duration_ms = (time.time() - start_time) * 1000
            logger.warning(json.dumps({
                **log_context,
                "message": "Validation error",
                "error": str(e),
                "duration_ms": round(duration_ms, 2),
            }))
            return _error_response(400, str(e), correlation_id)

        except Exception as e:
            duration_ms = (time.time() - start_time) * 1000
            logger.exception(json.dumps({
                **log_context,
                "message": "Unhandled exception",
                "error_type": type(e).__name__,
                "error": str(e),
                "duration_ms": round(duration_ms, 2),
            }))
            return _error_response(500, "Internal server error", correlation_id)

    return wrapper


def _detect_event_source(event):
    """Detect the event source type for logging."""
    if "Records" in event:
        records = event["Records"]
        if records:
            source = records[0].get("eventSource") or records[0].get("EventSource", "")
            if "sqs" in source.lower():
                return "sqs"
            if "sns" in source.lower():
                return "sns"
            if "s3" in source.lower():
                return "s3"
            if "dynamodb" in source.lower():
                return "dynamodb-stream"
    if "httpMethod" in event or "requestContext" in event:
        return "api-gateway"
    if "detail-type" in event:
        return "eventbridge"
    if "source" in event and event.get("source", "").startswith("aws."):
        return "aws-event"
    return "unknown"


def _error_response(status_code, message, correlation_id):
    """Build a consistent error response."""
    return {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "X-Correlation-Id": correlation_id,
        },
        "body": json.dumps({
            "error": message,
            "correlation_id": correlation_id,
            "service": SERVICE_NAME,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }),
    }


def _success_response(body, correlation_id, status_code=200):
    """Build a consistent success response."""
    return {
        "statusCode": status_code,
        "headers": {
            "Content-Type": "application/json",
            "X-Correlation-Id": correlation_id,
        },
        "body": json.dumps({
            "data": body,
            "correlation_id": correlation_id,
            "service": SERVICE_NAME,
            "timestamp": datetime.now(timezone.utc).isoformat(),
        }),
    }


