class DynamoDBService:
    """Common DynamoDB operations available to all microservices."""

    def __init__(self, table_name=None):
        self.table_name = table_name or DYNAMODB_TABLE
        self._table = None

    @property
    def table(self):
        if self._table is None:
            self._table = dynamodb_resource().Table(self.table_name)
        return self._table

    def get_item(self, key):
        response = self.table.get_item(Key=key)
        return response.get("Item")

    def put_item(self, item):
        item["updated_at"] = datetime.now(timezone.utc).isoformat()
        if "created_at" not in item:
            item["created_at"] = item["updated_at"]
        self.table.put_item(Item=item)
        return item

    def update_item(self, key, update_expression, expression_values, condition_expression=None):
        kwargs = {
            "Key": key,
            "UpdateExpression": update_expression,
            "ExpressionAttributeValues": expression_values,
            "ReturnValues": "ALL_NEW",
        }
        if condition_expression:
            kwargs["ConditionExpression"] = condition_expression
        response = self.table.update_item(**kwargs)
        return response.get("Attributes")

    def delete_item(self, key):
        self.table.delete_item(Key=key)

    def query(self, key_condition_expression, expression_values=None, index_name=None, limit=None):
        kwargs = {"KeyConditionExpression": key_condition_expression}
        if expression_values:
            kwargs["ExpressionAttributeValues"] = expression_values
        if index_name:
            kwargs["IndexName"] = index_name
        if limit:
            kwargs["Limit"] = limit
        response = self.table.query(**kwargs)
        return response.get("Items", [])


